const { execSync } = require('child_process');
let stdout = '';
try {
  stdout = execSync(
    'cd C:\\myapp && npx jest --json 2>nul',
    { encoding: 'utf8', timeout: 60000 }
  );
} catch (e) {
  stdout = e.stdout || '';
}
return [{ json: { stdout } }];

const body = $input.first().json.body || {};

const mockResponse = {
  status: "success",
  transaction_id: "MOCK-" + Date.now(),
  amount: body.amount || 0,
  currency: body.currency || "USD",
  timestamp: new Date().toISOString(),
  mocked: true
};

return [{ json: mockResponse }];

const { appendFileSync } = require('fs');
const d = $input.first().json;

const line = `${d.timestamp} | ${d.transaction_id} | amount: ${d.amount}\n`;
appendFileSync('C:\\myapp\\mock-log.txt', line);

return [{ json: d }];

const { readFileSync, writeFileSync, existsSync } = require('fs');
const snapshotPath = 'C:\\myapp\\api-snapshot.json';

// ✅ Only compare the body, ignore headers/date
const raw = $input.first().json;
const bodyOnly = raw.body || raw;  // HTTP Request puts body in .body
const current = JSON.stringify(bodyOnly, null, 2);

if (!existsSync(snapshotPath)) {
  writeFileSync(snapshotPath, current);
  return [{ json: {
    status: 'CREATED',
    message: 'First snapshot saved.',
    snapshot: current
  }}];
}

const previous = readFileSync(snapshotPath, 'utf8');

if (current === previous) {
  return [{ json: {
    status: 'MATCH',
    message: 'API response unchanged.',
    snapshot: current
  }}];
} else {
  return [{ json: {
    status: 'DIFF',
    message: 'API response has changed!',
    previous: previous,
    current: current
  }}];
}

const { execSync } = require('child_process');
let output = '';
try {
  output = execSync('node C:\\myapp\\screenshot.js', { encoding: 'utf8', timeout: 60000 });
} catch(e) {
  output = e.stdout || e.message || 'error';
}
let result;
try {
  result = JSON.parse(output.trim());
} catch(e) {
  result = { status: 'ERROR', message: output };
}
return [{ json: result }];

