const puppeteer = require('puppeteer');
const { writeFileSync, existsSync, readFileSync } = require('fs');

const screenshotPath = 'C:\\myapp\\current-screenshot.png';
const snapshotPath   = 'C:\\myapp\\saved-screenshot.png';
const logPath        = 'C:\\myapp\\snapshot-log.txt';

const browser = await puppeteer.launch({
  headless: true,
  executablePath: 'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe',
  args: [
    '--no-sandbox',
    '--disable-setuid-sandbox',
    '--disable-gpu',
    '--disable-dev-shm-usage'
  ]
});

const page = await browser.newPage();
await page.setViewport({ width: 1280, height: 720 });
await page.goto('http://localhost:3000', { waitUntil: 'networkidle0' });

const screenshot = await page.screenshot({ fullPage: true });
await browser.close();

writeFileSync(screenshotPath, screenshot);

if (!existsSync(snapshotPath)) {
  writeFileSync(snapshotPath, screenshot);
  const line = `${new Date().toISOString()} | Screenshot: CREATED ✅\n`;
  writeFileSync(logPath, line, { flag: 'a' });
  return [{ json: { 
    status: 'CREATED', 
    message: 'First screenshot snapshot saved!',
    path: screenshotPath
  }}];
}

const saved  = readFileSync(snapshotPath);
const isSame = Buffer.compare(saved, screenshot) === 0;

const line = `${new Date().toISOString()} | Screenshot: ${isSame ? 'MATCH ✅' : 'DIFF ⚠️'}\n`;
writeFileSync(logPath, line, { flag: 'a' });

if (isSame) {
  return [{ json: { 
    status: 'MATCH', 
    message: 'Screenshot unchanged ✅',
    path: screenshotPath
  }}];
} else {
  writeFileSync(snapshotPath, screenshot);
  return [{ json: { 
    status: 'DIFF', 
    message: 'Screenshot changed ⚠️ snapshot updated',
    path: screenshotPath
  }}];
}

